import { render, Box, Text } from 'ink';

function App() {
  return (
    <Box flexDirection="column">
      <Text color="green" bold>✓ Claude Code Ready</Text>
      <Text dimColor>Type /help to get started</Text>
    </Box>
  );
}

render(<App />);

type Command = '/commit' | '/review-pr' | '/rewrite' | '/test';

async function handleCommand(input: string) {
  const command = input.split(' ')[0] as Command;
  const args = input.slice(command.length).trim();

  switch (command) {
    case '/commit':
      return await commitHandler(args);
    case '/review-pr':
      return await reviewPrHandler(args);
    case '/rewrite':
      return await rewriteHandler(args);
    case '/test':
      return await testHandler(args);
    default:
      throw new Error(`Unknown command: ${command}`);
  }
}

interface Tool {
  name: string;
  description: string;
  parameters: {
    type: 'object';
    properties: Record<string, ParameterType>;
    required: string[];
  };
  execute(params: unknown): Promise<ToolResult>;
}

interface ToolResult {
  success: boolean;
  data?: unknown;
  error?: string;
}

